    "id": "automatic_payments_2.2.0_POST_pix_recurring-payments_chunk_12_f32f449f",
    "text_content": "Uma string com a utilização de timezone UTC-3 (UTC time format).\" }, \"payment\": { \"type\": \"object\", \"description\": \"Objeto contendo as informações do pagamento.\", \"required\": [ \"amount\", \"currency\" ], \"properties\": { \"amount\": { \"type\": \"string\", \"minLength\": 4, \"maxLength\": 19, \"pattern\": \"^((\\\\d{1,16}\\\\.\\\\d{2}))$\", \"example\": \"100000.12\", \"description\": \"Valor da transação com 2 casas decimais.\\n\" }, \"currency\": { \"type\": \"string\", \"maxLength\": 3, \"pattern\": \"^([A-Z]{3})$\", \"example\": \"BRL\", \"description\": \"Código da moeda nacional segundo modelo ISO-4217, ou seja, 'BRL'. Todos os valores monetários informados estão representados com a moeda vigente do Brasil.\\n\" } } }, \"creditorAccount\": { \"type\": \"object\", \"description\": \"Objeto que contém a identificação da conta de destino do beneficiário/recebedor.\\n\\n[Restrição] - Se /data/paymentReference = \\\"zero\\\", as informações da conta de crédito enviadas (/data/creditorAccount) devem ser iguais as presentes na conta de crédito informada na criação do consentimento(`/data/recurringConfiguration/automatic/firstPayment/creditorAccount`)\\n\", \"required\": [ \"ispb\", \"number\", \"accountType\" ], \"properties\": { \"ispb\": { \"type\": \"string\", \"minLength\": 8, \"maxLength\": 8, \"pattern\": \"^[0-9A-Z]{8}$\", \"example\": \"12345678\", \"description\": \"Deve ser preenchido com o ISPB (Identificador do Sistema de Pagamentos Brasileiros) do participante do SPI (Sistema de pagamentos instantâneos) somente com números.\\n\" }, \"issuer\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 4, \"pattern\": \"^[0-9]{1,4}$\", \"example\": \"1774\", \"description\": \"Código da Agência emissora da conta sem dígito. \\n(Agência é a dependência destinada ao atendimento aos clientes, ao público em geral e aos associados de cooperativas de crédito, \\nno exercício de atividades da instituição, não podendo ser móvel ou transitória).\\n\\n[Restrição] Preenchimento obrigatório para os seguintes tipos de conta: CACC (CONTA_DEPOSITO_A_VISTA) e SVGS (CONTA_POUPANCA).\\n\" }, \"number\": { \"type\": \"string\", \"minLength\": 1, \"maxLength\": 20, \"pattern\": \"^[0-9]{1,20}$\", \"example\": \"1234567890\", \"description\": \"Deve ser preenchido com o número da conta transacional do usuário recebedor, com dígito verificador (se este existir),\\nse houver valor alfanumérico, este deve ser convertido para 0.\\n\" }, \"accountType\": { \"type\": \"string\", \"enum\": [ \"CACC\", \"SVGS\", \"TRAN\" ], \"example\": \"CACC\", \"description\": \"Tipos de contas usadas para pagamento via Pix.\\nModalidades tradicionais previstas pela Resolução 4.753, não contemplando contas vinculadas,\\nconta de domiciliados no exterior, contas em moedas estrangeiras e conta correspondente moeda eletrônica.\\nSegue descrição de cada valor do ENUM para o escopo do Pix.\\n\\n- CACC - Current - Conta Corrente.\\n- SVGS - Savings - Conta de Poupança.\\n- TRAN - TransactingAccount - Conta de Pagamento pré-paga.\\n\" } } }, \"remittanceInformation\": { \"type\": \"string\", \"maxLength\": 140, \"pattern\": \"[\\\\w\\\\W\\\\s]*\", \"example\": \"Pagamento da nota XPTO035-002.\", \"description\": \"Deve ser preenchido sempre que o usuário pagador inserir alguma informação adicional em um pagamento, a ser enviada ao recebedor.\\n\" }, \"cnpjInitiator\": { \"type\": \"string\", \"pattern\": \"^[0-9A-Z]{12}[0-9]{2}$\", \"maxLength\": 14, \"example\": \"50685362000135\", \"description\": \"CNPJ do Iniciador de Pagamento devidamente habilitado para a prestação de Serviço de Iniciação no Pix.\" }, \"ibgeTownCode\": { \"type\": \"string\", \"minLength\": 7, \"maxLength\": 7, \"pattern\": \"^\\\\d{7}$\", \"example\": \"5300108\", \"description\": \"O campo ibgeTownCode no arranjo Pix tem o mesmo comportamento que o campo codMun descrito no item 1.6.6 do manual do Pix.\\n\\nCaso a informação referente ao município não seja enviada, o PSP do recebedor assumirá que não existem feriados estaduais e municipais no período em questão;\\n\" }, \"authorisationFlow\": { \"type\": \"string\", \"enum\": [ \"HYBRID_FLOW\", \"CIBA_FLOW\", \"FIDO_FLOW\" ], \"example\": \"HYBRID_FLOW\", \"description\": \"Campo condicional utilizado para identificar o fluxo de autorização em que o pagamento foi solicitado.\\n\\n[Restrição] Se CIBA ou FIDO, preenchimento obrigatório.",
    "title": "Cria uma transação de pagamento.",
